import React, { useState } from 'react';
import { sendMessage } from '../services/api';
import MessageBubble from './MessageBubble';
import './ChatWindow.css';

function ChatWindow() {
  const [messages, setMessages] = useState([
    {
      sender: 'bot',
      text: 'Hello. I’m your AI business assistant. How can I help you today?',
    },
  ]);

  const [input, setInput] = useState('');

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = {
      sender: 'user',
      text: input,
    };

    setMessages((prev) => [...prev, userMsg]);

    const history = messages.map((m) => [m.sender, m.text]);

    try {
      const response = await sendMessage(input, history);

      const botMsg = {
        sender: 'bot',
        text: response.reply,
      };

      setMessages((prev) => [...prev, botMsg]);
    } catch {
      const errorMsg = {
        sender: 'bot',
        text: 'Connection to server failed.',
      };

      setMessages((prev) => [...prev, errorMsg]);
    }

    setInput('');
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter') {
      handleSend();
    }
  };

  return (
    <div className="chat-window">

      {/* Header */}
      <div className="chat-header">
        <div>
          <h2>AI Assistant</h2>
          <span>Powered by Mistral AI</span>
        </div>
      </div>

      {/* Messages */}
      <div className="messages">
        {messages.map((msg, i) => (
          <MessageBubble
            key={i}
            text={msg.text}
            sender={msg.sender}
          />
        ))}
      </div>

      {/* Input */}
      <div className="input-area">
        <input
          type="text"
          value={input}
          placeholder="Ask something..."
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyPress}
        />

        <button onClick={handleSend}>
          Send
        </button>
      </div>
    </div>
  );
}

export default ChatWindow;
